import React, { useEffect, useMemo, useState } from 'react';
import adminService from '../../services/adminService';

const ASSIGNEE_POOL = ['Sarah Johnson', 'Mike Wilson', 'Ana Reyes', 'Mark Santos'];
const CONCERNS_CACHE_KEY = 'admin_concerns_cache_v1';

const readCachedConcerns = () => {
    try {
        const raw = localStorage.getItem(CONCERNS_CACHE_KEY);
        if (!raw) {
            return [];
        }

        const parsed = JSON.parse(raw);
        return Array.isArray(parsed) ? parsed : [];
    } catch {
        return [];
    }
};

const getPriority = (text = '') => {
    const value = String(text).toLowerCase();
    if (/(urgent|asap|failed|error|broken|refund)/.test(value)) return 'high';
    if (/(shipping|tracking|delay|status|cancel)/.test(value)) return 'medium';
    return 'low';
};

const getCategory = (text = '') => {
    const value = String(text).toLowerCase();
    if (/(refund|return|replace)/.test(value)) return 'Refund';
    if (/(shipping|delivery|tracking)/.test(value)) return 'Shipping';
    if (/(order|checkout|payment)/.test(value)) return 'Order Inquiry';
    return 'Technical Support';
};

const statusLabel = (status) => {
    if (status === 'pending') return 'open';
    if (status === 'reviewed') return 'in progress';
    if (status === 'resolved') return 'resolved';
    return status;
};

export default function AdminConcerns() {
    const cachedConcerns = readCachedConcerns();
    const [concerns, setConcerns] = useState(cachedConcerns);
    const [loading, setLoading] = useState(!cachedConcerns.length);
    const [error, setError] = useState('');
    const [query, setQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [priorityFilter, setPriorityFilter] = useState('all');
    const [page, setPage] = useState(1);
    const [activeConcern, setActiveConcern] = useState(null);
    const [replyText, setReplyText] = useState('');
    const [replyStatus, setReplyStatus] = useState('reviewed');
    const [sendingReply, setSendingReply] = useState(false);

    const pageSize = 6;

    useEffect(() => {
        loadConcerns();
    }, []);

    const loadConcerns = async () => {
        try {
            if (!loading) {
                setError('');
            }

            const params = {};
            if (statusFilter !== 'all') {
                params.status = statusFilter;
            }

            const res = await adminService.getCustomerConcerns(params);
            const nextConcerns = res.data.data.data || res.data.data || [];
            setConcerns(nextConcerns);
            localStorage.setItem(CONCERNS_CACHE_KEY, JSON.stringify(nextConcerns));
        } catch (err) {
            setError('Failed to load customer concerns');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!loading) {
            loadConcerns();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [statusFilter]);

    const updateConcernStatus = async (id, status) => {
        try {
            await adminService.updateCustomerConcern(id, { status });
            loadConcerns();
        } catch (err) {
            setError('Failed to update concern status');
        }
    };

    const openReplyModal = (concern) => {
        setActiveConcern(concern);
        setReplyText(concern.admin_reply || '');
        setReplyStatus(concern.status || 'reviewed');
        setError('');
    };

    const closeReplyModal = () => {
        setActiveConcern(null);
        setReplyText('');
        setReplyStatus('reviewed');
    };

    const sendReply = async () => {
        if (!activeConcern) {
            return;
        }

        if (!replyText.trim()) {
            setError('Reply message is required before sending.');
            return;
        }

        try {
            setSendingReply(true);
            setError('');
            await adminService.updateCustomerConcern(activeConcern.id, {
                status: replyStatus,
                admin_reply: replyText.trim(),
            });
            await loadConcerns();
            closeReplyModal();
        } catch (err) {
            setError('Failed to send reply to customer');
        } finally {
            setSendingReply(false);
        }
    };

    const filteredConcerns = useMemo(() => {
        const search = query.trim().toLowerCase();

        const enriched = concerns.map((concern, index) => {
            const joined = `${concern.subject || ''} ${concern.message || ''}`;
            const priority = getPriority(joined);
            const category = getCategory(joined);
            const assignedTo = ASSIGNEE_POOL[index % ASSIGNEE_POOL.length];

            return {
                ...concern,
                ticket_id: `TKT-${String(concern.id).padStart(3, '0')}`,
                priority,
                category,
                assigned_to: assignedTo,
                display_status: statusLabel(concern.status),
            };
        });

        return enriched.filter((concern) => {
            const haystack = [concern.name, concern.email, concern.subject, concern.message]
                .filter(Boolean)
                .join(' ')
                .toLowerCase();

            const matchesSearch = !search || haystack.includes(search) || concern.ticket_id.toLowerCase().includes(search);
            const matchesStatus = statusFilter === 'all' || concern.status === statusFilter;
            const matchesPriority = priorityFilter === 'all' || concern.priority === priorityFilter;

            return matchesSearch && matchesStatus && matchesPriority;
        });
    }, [concerns, query, statusFilter, priorityFilter]);

    const paginatedConcerns = useMemo(() => {
        const start = (page - 1) * pageSize;
        return filteredConcerns.slice(start, start + pageSize);
    }, [filteredConcerns, page]);

    const totalPages = Math.max(1, Math.ceil(filteredConcerns.length / pageSize));

    useEffect(() => {
        setPage(1);
    }, [query, statusFilter, priorityFilter]);

    useEffect(() => {
        if (page > totalPages) {
            setPage(totalPages);
        }
    }, [page, totalPages]);

    const summaryCards = useMemo(() => {
        const today = new Date().toDateString();

        return [
            { label: 'Open Tickets', value: concerns.filter((item) => item.status === 'pending').length, accent: 'blue', icon: 'chat' },
            { label: 'In Progress', value: concerns.filter((item) => item.status === 'reviewed').length, accent: 'purple', icon: 'clock' },
            { label: 'Pending', value: concerns.filter((item) => item.status === 'pending').length, accent: 'yellow', icon: 'alert' },
            {
                label: 'Resolved Today',
                value: concerns.filter((item) => item.status === 'resolved' && new Date(item.updated_at || item.created_at).toDateString() === today).length,
                accent: 'green',
                icon: 'check',
            },
        ];
    }, [concerns]);

    const formatDate = (value) => (value ? new Date(value).toLocaleString() : '-');

    return (
        <div className="admin-page-content admin-concerns-page">
            <div className="concerns-header-row">
                <div>
                    <h2>Customer Service</h2>
                    <p>Manage support tickets and customer inquiries</p>
                </div>
            </div>

            {error && <div className="alert alert-danger">{error}</div>}

            <section className="concerns-summary-grid">
                {summaryCards.map((card) => (
                    <article key={card.label} className={`concern-summary-card concern-summary-card--${card.accent}`}>
                        <div>
                            <p>{card.label}</p>
                            <strong>{card.value}</strong>
                        </div>
                        <span className={`concern-summary-icon concern-summary-icon--${card.icon}`} />
                    </article>
                ))}
            </section>

            <div className="concerns-panel">
                <div className="concerns-toolbar">
                    <div className="concerns-search">
                        <input
                            type="text"
                            placeholder="Search tickets by ID, customer, or subject..."
                            value={query}
                            onChange={(e) => setQuery(e.target.value)}
                        />
                    </div>
                    <div className="concerns-filter">
                        <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="form-control">
                            <option value="all">All Status</option>
                            <option value="pending">Pending</option>
                            <option value="reviewed">Reviewed</option>
                            <option value="resolved">Resolved</option>
                        </select>
                    </div>
                    <div className="concerns-filter">
                        <select value={priorityFilter} onChange={(e) => setPriorityFilter(e.target.value)} className="form-control">
                            <option value="all">All Priorities</option>
                            <option value="high">High</option>
                            <option value="medium">Medium</option>
                            <option value="low">Low</option>
                        </select>
                    </div>
                </div>

                <div className="concerns-table">
                    <table>
                        <thead>
                            <tr>
                                <th>Ticket</th>
                                <th>Customer</th>
                                <th>Subject</th>
                                <th>Category</th>
                                <th>Priority</th>
                                <th>Status</th>
                                <th>Assigned To</th>
                                <th>Last Updated</th>
                                <th>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {!loading && paginatedConcerns.length > 0 ? paginatedConcerns.map((concern) => (
                                <tr key={concern.id}>
                                    <td className="concern-ticket-cell">{concern.ticket_id}</td>
                                    <td>
                                        <div className="concern-customer-cell">
                                            <strong>{concern.name || '-'}</strong>
                                            <span>{concern.email || '-'}</span>
                                        </div>
                                    </td>
                                    <td>{concern.subject || '-'}</td>
                                    <td>{concern.category}</td>
                                    <td>
                                        <span className={`concern-priority concern-priority--${concern.priority}`}>{concern.priority}</span>
                                    </td>
                                    <td>
                                        <span className={`concern-status concern-status--${concern.display_status.replace(' ', '-')}`}>
                                            {concern.display_status}
                                        </span>
                                    </td>
                                    <td>{concern.assigned_to}</td>
                                    <td>{formatDate(concern.updated_at || concern.created_at)}</td>
                                    <td>
                                        <div className="concern-action-wrap">
                                            <button type="button" className="view-btn" title={concern.message || 'No details'}>
                                                View
                                            </button>
                                            <button type="button" className="view-btn" onClick={() => openReplyModal(concern)}>
                                                Reply
                                            </button>
                                            <select
                                                value={concern.status}
                                                onChange={(e) => updateConcernStatus(concern.id, e.target.value)}
                                                className="status-select"
                                            >
                                                <option value="pending">Open</option>
                                                <option value="reviewed">In Progress</option>
                                                <option value="resolved">Resolved</option>
                                            </select>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan="9" className="concerns-empty-state">
                                        {loading ? 'Please wait...' : 'No customer concerns found.'}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                <div className="concerns-pagination">
                    <span>Showing {filteredConcerns.length} of {concerns.length} tickets</span>
                    <div className="concerns-pagination-actions">
                        <button type="button" disabled={page <= 1} onClick={() => setPage((prev) => Math.max(1, prev - 1))}>Previous</button>
                        <button type="button" disabled={page >= totalPages} onClick={() => setPage((prev) => Math.min(totalPages, prev + 1))}>Next</button>
                    </div>
                </div>
            </div>

            {activeConcern && (
                <div
                    role="dialog"
                    aria-modal="true"
                    className="modal-backdrop"
                    style={{
                        position: 'fixed',
                        inset: 0,
                        background: 'rgba(15, 23, 42, 0.5)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        zIndex: 2000,
                        padding: '1rem',
                    }}
                    onClick={closeReplyModal}
                >
                    <div
                        className="form-card"
                        style={{
                            width: 'min(680px, 96vw)',
                            background: '#ffffff',
                            borderRadius: '12px',
                            border: '1px solid #dbe1ea',
                            padding: '1rem',
                        }}
                        onClick={(e) => e.stopPropagation()}
                    >
                        <div className="modal-header" style={{ marginBottom: '0.8rem' }}>
                            <h2 style={{ margin: 0 }}>Reply to Customer</h2>
                            <button type="button" className="modal-close" onClick={closeReplyModal}>Close</button>
                        </div>

                        <div style={{ border: '1px solid #e2e8f0', borderRadius: '10px', padding: '0.75rem', marginBottom: '0.8rem', background: '#f8fafc' }}>
                            <p style={{ margin: 0, fontWeight: 700, color: '#0f172a' }}>{activeConcern.subject || 'No Subject'}</p>
                            <p style={{ margin: '0.25rem 0 0', color: '#334155' }}>{activeConcern.message || 'No customer message provided.'}</p>
                        </div>

                        <div className="form-group" style={{ marginBottom: '0.65rem' }}>
                            <label htmlFor="admin-reply-status">Status</label>
                            <select
                                id="admin-reply-status"
                                value={replyStatus}
                                onChange={(e) => setReplyStatus(e.target.value)}
                                disabled={sendingReply}
                            >
                                <option value="pending">Open</option>
                                <option value="reviewed">In Progress</option>
                                <option value="resolved">Resolved</option>
                            </select>
                        </div>

                        <div className="form-group">
                            <label htmlFor="admin-reply-text">Reply Message</label>
                            <textarea
                                id="admin-reply-text"
                                rows="6"
                                value={replyText}
                                onChange={(e) => setReplyText(e.target.value)}
                                placeholder="Type your reply to the customer..."
                                disabled={sendingReply}
                            />
                        </div>

                        <div style={{ marginTop: '0.75rem', display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                            <button type="button" className="btn btn-outline" onClick={closeReplyModal} disabled={sendingReply}>Cancel</button>
                            <button type="button" className="btn btn-primary" onClick={sendReply} disabled={sendingReply}>
                                Send Reply
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}